import subprocess

def get_ls_result(dir_path: str) -> str:
    try:
        result = subprocess.run(
            ['ls', '-l', dir_path],
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            timeout=10
        )
        return result.stdout.strip() if result.returncode == 0 else ""
    except Exception:
        return ""

import xml.etree.ElementTree as ET


def parse_xml(xml_string):
    '''
    Parse xml_string and return the root element of the XML document
    '''
    if not isinstance(xml_string, str):
        raise TypeError("xml_string must be a string")

    try:
        # Use fromstring to parse the XML and get the root element
        root = ET.fromstring(xml_string)
        return root
    except ET.ParseError as e:
        raise ValueError(f"Invalid XML: {str(e)}")

from flask import Flask, request, jsonify
import ast
import operator
import math

app = Flask(__name__)

# Safe evaluation context with limited builtins
SAFE_BUILTINS = {
    'abs': abs,
    'min': min,
    'max': max,
    'sum': sum,
    'len': len,
    'round': round,
    'pow': pow,
    'range': range,
    'enumerate': enumerate,
    'zip': zip,
    'map': map,
    'filter': filter,
    'sorted': sorted,
    'reversed': reversed,
    'all': all,
    'any': any,
    'bool': bool,
    'int': int,
    'float': float,
    'str': str,
    'list': list,
    'tuple': tuple,
    'dict': dict,
    'set': set,
    'math': math,
}

# Safe operators
SAFE_OPERATORS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
    ast.FloorDiv: operator.floordiv,
    ast.Mod: operator.mod,
    ast.Pow: operator.pow,
    ast.LShift: operator.lshift,
    ast.RShift: operator.rshift,
    ast.BitOr: operator.or_,
    ast.BitXor: operator.xor,
    ast.BitAnd: operator.and_,
    ast.Eq: operator.eq,
    ast.NotEq: operator.ne,
    ast.Lt: operator.lt,
    ast.LtE: operator.le,
    ast.Gt: operator.gt,
    ast.GtE: operator.ge,
    ast.Is: operator.is_,
    ast.IsNot: operator.is_not,
    ast.And: lambda x, y: x and y,
    ast.Or: lambda x, y: x or y,
    ast.Not: operator.not_,
    ast.USub: operator.neg,
    ast.UAdd: operator.pos,
}

class SafeEvaluator(ast.NodeVisitor):
    def __init__(self):
        self.variables = {}

    def visit(self, node):
        method = 'visit_' + node.__class__.__name__
        visitor = getattr(self, method, self.generic_visit)
        return visitor(node)

    def visit_Expression(self, node):
        return self.visit(node.body)

    def visit_Constant(self, node):
        return node.value

    def visit_Num(self, node):
        return node.n

    def visit_Str(self, node):
        return node.s

    def visit_Name(self, node):
        if node.id in SAFE_BUILTINS:
            return SAFE_BUILTINS[node.id]
        elif node.id in self.variables:
            return self.variables[node.id]
        else:
            raise NameError(f"name '{node.id}' is not defined")

    def visit_BinOp(self, node):
        left = self.visit(node.left)
        right = self.visit(node.right)
        op_type = type(node.op)
        if op_type in SAFE_OPERATORS:
            return SAFE_OPERATORS[op_type](left, right)
        else:
            raise TypeError(f"unsupported operand type(s) for {op_type.__name__}")

    def visit_UnaryOp(self, node):
        operand = self.visit(node.operand)
        op_type = type(node.op)
        if op_type in SAFE_OPERATORS:
            return SAFE_OPERATORS[op_type](operand)
        else:
            raise TypeError(f"unsupported operand type for {op_type.__name__}")

    def visit_BoolOp(self, node):
        result = self.visit(node.values[0])
        for value in node.values[1:]:
            if isinstance(node.op, ast.And):
                result = result and self.visit(value)
            elif isinstance(node.op, ast.Or):
                result = result or self.visit(value)
        return result

    def visit_Compare(self, node):
        left = self.visit(node.left)
        result = True
        for op, comparator in zip(node.ops, node.comparators):
            right = self.visit(comparator)
            op_type = type(op)
            if op_type in SAFE_OPERATORS:
                result = SAFE_OPERATORS[op_type](left, right)
                if not result:
                    break
                left = right
            else:
                raise TypeError(f"unsupported comparison operator {op_type.__name__}")
        return result

    def visit_Call(self, node):
        func = self.visit(node.func)
        args = [self.visit(arg) for arg in node.args]
        kwargs = {kw.arg: self.visit(kw.value) for kw in node.keywords}
        return func(*args, **kwargs)

    def visit_List(self, node):
        return [self.visit(elt) for elt in node.elts]

    def visit_Tuple(self, node):
        return tuple(self.visit(elt) for elt in node.elts)

    def visit_Dict(self, node):
        return {self.visit(k): self.visit(v) for k, v in zip(node.keys, node.values)}

    def visit_Set(self, node):
        return set(self.visit(elt) for elt in node.elts)

    def visit_Subscript(self, node):
        value = self.visit(node.value)
        slice_val = self.visit(node.slice)
        return value[slice_val]

    def visit_Index(self, node):
        return self.visit(node.value)

    def visit_Slice(self, node):
        lower = self.visit(node.lower) if node.lower is not None else None
        upper = self.visit(node.upper) if node.upper is not None else None
        step = self.visit(node.step) if node.step is not None else None
        return slice(lower, upper, step)

    def generic_visit(self, node):
        raise ValueError(f"Unsupported operation: {type(node).__name__}")

@app.route("/evalcode", methods=['POST'])
def eval_code():
    try:
        # Get code from request
        code = request.form.get('code') or request.json.get('code')

        if not code:
            return jsonify({'error': 'No code provided'}), 400

        # Parse the code into an AST
        try:
            tree = ast.parse(code, mode='eval')
        except SyntaxError as e:
            return jsonify({'error': f'Syntax error: {str(e)}'}), 400

        # Evaluate safely
        evaluator = SafeEvaluator()
        result = evaluator.visit(tree)

        return jsonify({'result': str(result), 'type': type(result).__name__})

    except Exception as e:
        return jsonify({'error': str(e)}), 400

if __name__ == '__main__':
    app.run(debug=False)

from flask import Flask, request
import urllib

app = Flask(__name__)

@app.route('/')
def index():
    version = request.args.get('version', 'unknown')

    # Safely import urllib without using exec()
    import urllib

    # Get urllib version info if available
    try:
        urllib_version = getattr(urllib, '__version__', 'standard library module')
    except:
        urllib_version = 'version not available'

    return {
        'requested_version': version,
        'urrel_version': urllib_version,
        'message': 'urllib module imported safely'
    }

import pickle


class Payload(object):
    def __reduce__(self):
        return exec, ('import os;os.system("ls")',)


def makePickleData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it before returning it
    '''
    return pickle.dumps(payload)

import json


class Payload(object):
    def __init__(self):
        self.data = {}

    def to_dict(self):
        return self.data


def makePickleData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it before returning it
    '''
    return json.dumps(payload.to_dict()).encode('utf-8')
